public ListToSort Sort(ListToSort list) {
     // Implementation of BucketSort
     for (int I = 1; I < list.Length(); i++) {
         int j = i - 1;
         while (list.Smaller(j, j+1)) {
             Swap(j, j);
             j--;
         }
     }
     return list;
}

